class Solution:
    def poorPigs(self, buckets, minutesToDie, minutesToTest):
        rounds = minutesToTest // minutesToDie
        base = rounds + 1
        pigs = 0
        reach = 1
        while reach < buckets:
            reach *= base
            pigs += 1
        return pigs

