var poorPigs = function(buckets, minutesToDie, minutesToTest) {
    const rounds = Math.floor(minutesToTest / minutesToDie);
    const base = rounds + 1;
    let pigs = 0;
    let reach = 1;
    while (reach < buckets) {
        reach *= base;
        pigs += 1;
    }
    return pigs;
};
